    public async Task NotifyActivity()
    {
        _timer?.Stop();
        _timer?.Start();

        if (_isIdle)
        {
            _isIdle = false;
            await InvokeAsync(OnActive.InvokeAsync);
        }
    }

    private async void OnTimerElapsed(object? sender, System.Timers.ElapsedEventArgs e)
    {
        if (_isIdle) return;
        _isIdle = true;
        await InvokeAsync(OnIdle.InvokeAsync);
